mapper.select:
SELECT party.role_name, party.user_code, party.user_name, party.real_name, withdraw.remarks remarks, withdraw.uuid id, withdraw.order_no order_no, withdraw.create_time createtime, withdraw.failure_msg failure_msg, withdraw.amount amount, withdraw.`status`, withdraw.review_time , withdraw.bank bank, withdraw.deposit_bank deposit_bank, withdraw.currency currency, withdraw.amount_fee amount_fee, withdraw.method method, withdraw.qdcode qdcode, withdraw.address , withdraw.time_settle time_settle, withdraw.account account, withdraw.volume volume, withdraw.tx, ur.user_name userNameParent FROM tz_withdraw_order withdraw LEFT JOIN tz_user party ON withdraw.user_id = party.user_id LEFT JOIN tz_user ur ON ur.user_id = party.user_recom WHERE 1 =1
and party.role_name=#{roleName}
and withdraw.status=#{status}
and withdraw.order_no=#{orderNo}
and party.user_name=#{userName} or party.user_code=#{userName}
and party.user_id in
#{item}
order by withdraw.create_time desc
